#!/usr/bin/env python3
"""
generate_resources.py

Appends:
 - 245 new item entries to assets/res/inf/items.inf
 - 300 new enemy entries to assets/res/inf/enemies.inf

Safe placeholder values; edit the generation logic if you want different balance/names.
