from pathlib import Path

ROOT = Path(".")
ITEMS_INF = ROOT / "assets" / "res" / "inf" / "items.inf"
ENEMIES_INF = ROOT / "assets" / "res" / "inf" / "enemies.inf"

NUM_ITEMS = 245
ITEM_START_ID = 100

NUM_ENEMIES = 300
BOSS_EVERY = 30
WORLD_BOSS_AT = [NUM_ENEMIES - 1, NUM_ENEMIES - 2]

def fmt_hex(n):
    return format(n, "X")

def append_items():
    if not ITEMS_INF.exists():
        raise FileNotFoundError(f"{ITEMS_INF} not found")
    lines = []
    id_num = ITEM_START_ID
    n_weapons = int(NUM_ITEMS * 0.60)
    n_armors = int(NUM_ITEMS * 0.35)
    n_rest = NUM_ITEMS - (n_weapons + n_armors)
    for i in range(n_weapons):
        name = f"Weapon_{id_num}"
        buy = 1000 + i * 10
        sell = buy // 2
        atk = 10 + (i // 10)
        lines.append(f"weapon {id_num},  {name}  , {buy:6d} , {sell:5d} , {atk:3d} , {0:2d} , {1:8d} ,     false , false ,     false ,             1 ,               false ,        false ,           false ,           false ,                    0")
        id_num += 1
    for i in range(n_armors):
        name = f"Armor_{id_num}"
        buy = 1200 + i * 12
        sell = buy // 2
        defv = 5 + (i // 10)
        lines.append(f"armor {id_num},  {name}  , {buy:6d} , {sell:5d} , {0:3d} , {defv:2d} , {1:8d} ,     false , false ,     false ,             1 ,               false ,        false ,           false ,           false ,                    0")
        id_num += 1
    for i in range(n_rest):
        if i % 2 == 0:
            name = f"Shield_{id_num}"
            buy = 900 + i * 5
            sell = buy // 2
            defv = 6 + (i // 4)
            lines.append(f"shield {id_num},  {name}  , {buy:6d} , {sell:5d} , {0:3d} , {defv:2d} , {1:8d} ,     false , false ,     false ,             1 ,               false ,        false ,           false ,           false ,                    0")
        else:
            name = f"Item_{id_num}"
            buy = 100 + i * 3
            sell = buy // 3
            lines.append(f"item   {id_num},  {name}  , {buy:6d} , {sell:5d} , {0:3d} , {0:2d} , {6:8d} ,      true ,  true ,     true ,             6 ,               false ,        false ,           false ,           false ,                    0")
        id_num += 1

    with open(ITEMS_INF, "a", encoding="utf-8") as f:
        f.write("\n# --- GENERATED ITEMS START ---\n")
        for l in lines:
            f.write(l + "\n")
        f.write("# --- GENERATED ITEMS END ---\n")
    print(f"Appended {len(lines)} items (IDs {ITEM_START_ID}..{id_num-1})")

def find_highest_enemy_hex():
    last = -1
    with open(ENEMIES_INF, "r", encoding="utf-8") as f:
        for raw in f:
            line = raw.strip()
            if not line or line.startswith("#") or line.startswith(";"):
                continue
            parts = line.split(",")
            if len(parts) < 2:
                continue
            id_token = parts[0].strip()
            try:
                val = int(id_token, 16)
                last = max(last, val)
            except:
                pass
    return last

def append_enemies():
    highest = find_highest_enemy_hex()
    start = highest + 1
    entries = []
    for i in range(NUM_ENEMIES):
        cur = start + i
        hexid = fmt_hex(cur)
