        strv = 5 + (i // 10)
        agi = 3 + (i // 12)
        hp = 3 + (i // 8)
        pat = 0
        sr = 0x0F
        dr = 0x01
        xp = 1 + (i // 6)
        gp = 1 + (i // 8)
        groupId = (i % 8) + 1
        finalBoss = "false"
        if (i+1) % BOSS_EVERY == 0:
            finalBoss = "true"
            strv += 20; agi += 10; hp += 20; pat = 0x80; sr = 0xF0; dr = 0xF0; xp += 50; gp += 50
        if i in WORLD_BOSS_AT:
            finalBoss = "true"
            strv += 40; agi += 20; hp += 60; pat = 0xF0; sr = 0xFF; dr = 0xFF; xp += 500; gp += 500; groupId = 8
        parts = [
            hexid,
            f"  {name}  ",
            format(strv, "X"),
            format(agi, "X"),
            format(hp, "X"),
            format(pat, "X"),
            format(sr, "X"),
            format(dr, "X"),
            format(xp, "X"),
            format(gp, "X"),
            format(groupId, "X"),
            finalBoss
        ]
        entries.append(", ".join(parts))
    with open(ENEMIES_INF, "a", encoding="utf-8") as f:
        f.write("\n# --- GENERATED ENEMIES START ---\n")
        for l in entries:
            f.write(l + "\n")
        f.write("# --- GENERATED ENEMIES END ---\n")
    print(f"Appended {len(entries)} enemies (hex IDs {fmt_hex(start)} .. {fmt_hex(start + len(entries) - 1)})")

def main():
    append_items()
    append_enemies()
    print("Generation finished. Build and run the project to validate.")

if __name__ == '__main__':
    main()
